import net.minecraft.network.play.client.C13PacketPlayerAbilities;

public class AbilitiesDisabler extends Mode<Disabler> {

    public AbilitiesDisabler(String name, Disabler parent) {
        super(name, parent);
    }

    @Override
    public void onEnable() {
        // Send initial abilities with extreme values on enable
        PacketUtil.sendNoEvent(new C13PacketPlayerAbilities() {
            {
                this.flySpeed = Float.intBitsToFloat(0x7fc00000);  // NaN
                this.walkSpeed = Float.intBitsToFloat(0x7fc00000);  // NaN
            }
        });
    }

    @EventLink()
    public final Listener<PacketSendEvent> onPacketSend = event -> {
        // Block the vanilla C13 from being sent (the client sends it when flying state changes)
        if (event.getPacket() instanceof C13PacketPlayerAbilities) {
            event.setCancelled(true);
        }
    };

    @EventLink()
    public final Listener<PreMotionEvent> onPreMotion = event -> {
        // Send the corrupted abilities every 20 ticks on pre-motion
        // This ensures the server always has our bad abilities in its cache
        if (mc.thePlayer.ticksExisted % 20 == 0 && !BlinkComponent.blinking && !BadPacketsComponent.bad()) {
            PacketUtil.sendNoEvent(new C13PacketPlayerAbilities() {
                {
                    invulnerable = true;
                    isFlying = true;
                    allowFlying = true;
                    isCreativeMode = true;
                    flySpeed = Float.NaN;
                    walkSpeed = Float.NaN;
                }
            });
        }
    };
}

// Vanilla C13PacketPlayerAbilities definition (from all clients):
package net.minecraft.network.play.client;

import net.minecraft.entity.player.PlayerCapabilities;

public class C13PacketPlayerAbilities implements Packet<INetHandlerPlayServer> {
    private boolean invulnerable;
    private boolean isFlying;
    private boolean allowFlying;
    private boolean isCreativeMode;
    private float flySpeed;
    private float walkSpeed;

    public C13PacketPlayerAbilities() {}

    public C13PacketPlayerAbilities(PlayerCapabilities capabilities) {
        this.invulnerable = capabilities.disableDamage;
        this.isFlying = capabilities.isFlying;
        this.allowFlying = capabilities.allowFlying;
        this.isCreativeMode = capabilities.isCreativeMode;
        this.flySpeed = capabilities.getFlySpeed();
        this.walkSpeed = capabilities.getWalkSpeed();
    }

    public void readPacketData(PacketBuffer buf) throws IOException {
        byte flags = buf.readByte();
        this.invulnerable = (flags & 1) > 0;
        this.isFlying = (flags & 2) > 0;
        this.allowFlying = (flags & 4) > 0;
        this.isCreativeMode = (flags & 8) > 0;
        this.flySpeed = buf.readFloat();
        this.walkSpeed = buf.readFloat();
    }

    public void writePacketData(PacketBuffer buf) throws IOException {
        byte flags = 0;
        if (this.invulnerable) flags |= 1;
        if (this.isFlying) flags |= 2;
        if (this.allowFlying) flags |= 4;
        if (this.isCreativeMode) flags |= 8;
        buf.writeByte(flags);
        buf.writeFloat(this.flySpeed);
        buf.writeFloat(this.walkSpeed);
    }

    public boolean isInvulnerable() { return this.invulnerable; }
    public boolean isFlying() { return this.isFlying; }
    public boolean isAllowFlying() { return this.allowFlying; }
    public boolean isCreativeMode() { return this.isCreativeMode; }
    public float getFlySpeed() { return this.flySpeed; }
    public float getWalkSpeed() { return this.walkSpeed; }
}

